window.SITE = {"author":"burak biçer","hero":"harflerden kurmuşum şehirleri","sections":[{"id":"siirler","name":"Şiirler","pieces":[{"id":"dus-erken-yokusa","title":"Düş Erken Yokuşa","date":"4 gün önce","type":"verse","epigraph":null,"body":["Yol diye gördüğüm yolun karşısı bir ufuk çizgisi","Gördüklerime hangi muamele bu sefer","Bir gerçek gibi elleriyle söylediği hakikat","Ya da buna bir sınır mı durmanın taş sokaklarında","","Soruydu, doğanın ilk halinin yazısız zamanlarına","Eskimişliğin kattığı süreklilik adına veresiye","Açalım pencereli lütfen günler meşgul uzamakla","Lityum-iyon piller aşkına daha dört teker, daha dünya papatya","","Kalkalım, kalkalım olmadık beklenenlerin gelmeyenlerinden sonra","Biraz sinema ihtiyacı, yeni bir şeyler oyalanmaya dar vaktimizin gündüzüne","Savuralım mı bulamadığımız eğlenceyi","Yüklenelim mi bir günü daha dünü aynı saatlerine değen alnımıza","","Yine de sonra gidelim, bir bakarsın kaybolur anahtar","Çalışmaz olur gidilmesi gerekene lazım müstesna","Sonra denmelidir yüzün yüzündeyken güzel diye yüzüme","İşte bak o zaman yerli yerine, raylı rayına çalgı çengi olur sonra sokak"]},{"id":"gerisi","title":"Gerisi","date":"29 gün önce","type":"verse","epigraph":null,"body":["biraz yokuş, biraz taş sokak","biraz da unutulmuş iskele sesleri","bir evin tavan arasına sinmiş hatırasıdır durduğum","çünkü insan yarım kalan bir tarih","","kıyıya vurmayı unutan bir dalganın sabahı","köhne bir evin göğsünde duran saat","bütün vakitleri eskiten bir suskunluk","size sesleniyorum: Yağmurlar da gelir, yağmurlar...","","niyedir bir şehri büyüttüğüm?","bir akşamüstü, belki Eylül, belki değil","tanıdık gölgelerin ellerine duyduğum güven","bir şehirse bu, neden arkasını döner?","neden hep uzaklara gider kuşlar bile göçmeyi unutmuşken?","","Kuşların sesi bir hikayeye dönüşeli","ağır ağır topluyor suskunluğunu çarşılar","çünkü insan yarım kalan bir tarih","çünkü yağmurlar da bilir omuzlarından devrilmiş","şurada ay, ışığı eksilmiş","gölgesi fazla bir keder","kim bilir kim taşırdı bu kadar sessizliği","","bak, şimdi yine aynı masa","aynı çatlaklar aynı köhne duvar","oturmuşuz, bir gölge gibi içimde herkes","gerisi mi?","","boş bir tabureye anlatırken her şeyi","birden çoğaldı yanımdakiler (yanımda insanlar)"]},{"id":"tip-cubuguyla-raks","title":"Tip çubuğuyla raks","date":"1 ay önce","type":"verse","epigraph":null,"body":["alışma zaman sürüsünün telaşına","her türlüsü uzaklık sevginin","yalnızlık keşfedilmez beklerken treni","sanıklar ayağa kalksın","son yolcuyu gören kim?","","tüm sesleri sonuçsuz bir ezgiyle bocalanmış","gözyaşlarından büyük ağlıyor çocuklar bu kenti","koridorun sonunda hep aynı başlangıç","sanıklar ayağa kalksın","son noktayı koyan kim?","","önceki hikayenin önyargısı","kötürüm daktilonun gölgesinde saklı","şeritlerindeki rengi vuran tip çubuğu öfkesi şimdi","bir ormanı en çok yapraklarının tükendiği yerde avlarsın","yükselenim oğlak bu geceyi çıkaramazsın","sanıklar ayağa kalksın","son yaprağı inciten kim?"]},{"id":"sonra-susmuslar","title":"Sonra Susmuşlar","date":"1 ay önce","type":"verse","epigraph":{"art":"Early Sunday Morning - Edward Hopper, 1930","quote":null},"body":["sadece susmanın verdiği mi bilmiyorum","dilimin uğrağı marazi sözlere revolver","üstüne İspanyolca bir hüzün şarjör boşalmış","işte tarih elimizde kurumayan leke kan","","de ki","kimiz biz?","","hazırlıksız bir yanıta yakalanır da ıslanır insan","iblis şifresini unutunca kapılar ateşten olurmuş","gizli bir çay bahçesidir hiç şüphesiz","mevsimleri boşluğuna Hazerfan","","de ki","","bahar gelmiş apansız","felçli bir ceset burada, hâlâ çürümemiş","","yine de unutma, de ki","neyin yerine tutsak bu sabahın yedisi?","Uçurumun dibindeki bu doymazlık","","şöyleydi: masallar sonsuzluğa durmasını emretmiş","yanılgının göğünde her şey geriye doğru akmış","sorulmuş işte o ara bir sabah uykusunun uyanmayan yanları","evveliyatı insanın bir yabancının yolculuğunda:","","Tanrım, bunca göz sağanağı arasında neden yalnızım?","","sonra susmuşlar","sonra daha çok susmuşlar","sonra daha çok susmuşlar..."],"image":"images/sonra-susmuslar-hopper.jpg"},{"id":"erimsiz-kelimeler-kulliyati-i","title":"Erimsiz Kelimeler Külliyatı - I","date":"3 yıl önce","type":"verse","epigraph":null,"body":["Baktığımızda, kötümser bir ihtimal elimizdeki","başına buyruk bu rüzgar, uzaklarıyla dolanıyor üstelik","kırıldıklarımıza sayıyor bir turna sürüsü bunları","kanat kanat bulutlarıyla süzgün","yani, sadece bir armağan göğsümüzdeki ağrıya öylece","","Niyeyse bir baş dönmesi uyum içinde","sessiz kaldıklarımıza sayıyor bir akrep","-neden olmasın?-","dolaysız bir akrep","yelkovanı görmezden geliyor üstelik","en hızlı kirlenenlerine sayıyor","renk renk gölgeleriyle","","Aslında masalı anlatalı çok oldu, alıngandır bu yüzden süsenler","kırar boyunlarını yaprak yaprak güneşliyken hava üstelik","annemin beklediklerine sayıyor yine bir yağmur","toprak toprak taze üstelik","","Şu sokak yok mu, bazen İpek Yolu","belki bir atlas kaybolan yüzlerinde","bir satır sonu belki de Aragon’un kalbinde","velev ki hantal bir divit ucuna kaçar bazen dilim","damla damla baldıran üstelik.","","Görmüşsünüzdür bir kedinin gözlerinde","yaşadıklarımıza sayıyor bir çekirge sürüsü bunları üstelik","o sırada gülüyoruz ya sol elimize, anlaşılıyor bir şekilde","yani, sadece bir armağan göğsümüzdeki ağrıyla öylece","","Bense inatçıyım bir ısrarın köşesinde","hem insan utanabilir bir yerde","Lorca’nın mezarına kar yağarken","tane tane usulca üstelik."]},{"id":"erimsiz-kelimeler-kulliyati-ii","title":"Erimsiz Kelimeler Külliyatı - II","date":"3 yıl önce","type":"verse","epigraph":null,"body":["gecenizin bir vakti","çocukluğunuzdan esrik,","yani kötülük diye tanıtılan siyahtan kallavi","merhabasız iki duvarın az önce dünyaya küstüğü","asabi bir dönemeçteydim","","bağışlayın gözlerimi","bunları yitik bir kaldırımdan öğrendim","doğrusu birinin hatırlanan olmaktan usanmış sesiydim","","telaşsız bir gündüz hissiyle uyanmıştım ilk defa","bir serçenin neye üzüldüğünü öğrendim","bir martının anlattıklarına şaşırdım sonra","amonyak çiçeğinin masamızdaki","yapraklarını sererken,","kimsesizliğini bir güz akşamında","","bağışlayın gelmeyişimi","bir susmak günü ilan edilmişti o gün","bunları ürkütücü bir kentin tenhalığından getirdim","doğrusu birinin kaybolan uykusuydum","tarihi geçmiş çocuksuluğunda","","bağışlayın bunları yazmak istemezdim","hem eski normale dönemeyiz","üstelemeyin kardeşim","bazı kelimelerin kalbimi ziyaret etmek istemediğini öğrendim","","daha hızlı soğuyan şeylerin ortasında","hissizleşmiş parmaklarımla sevmeyi","bir cümle sanarak dudaklarınızdan çıkan kelimeleri","bir gerçeği daha kucaklamayı öğrendim","","çünkü gecenizin bir vakti","çocukluğunuzdan esrik,","yani kötülük diye tanıtılan siyahtan kallavi","altı çizili iki kelimenin az önce dünyaya küstüğü","asabi bir dönemeçteydim"]},{"id":"erimsiz-kelimeler-kulliyati-iii","title":"Erimsiz Kelimeler Külliyatı - III","date":"3 yıl önce","type":"verse","epigraph":null,"body":["sürekli dönüşen bir sessizlik","çözülüyor","sıvı haliyle yayılan kapı eşiklerine","ki bu sırada gözlerim yasal olmayanınmışçasına","ellerim boşluksuzmuşçasına","sıvı haline aldanıyor bu adsızlığımızın","","dönüşmek üzerine kurulu bir soru oluyor dudakların","bu arada günlerimin rengini merak ediyorsun","bazen biliyormuşçasına soruyorsun","bazense soruyormuşçasına","","çoğunlukla merdivensiz dolaştığımı biliyor sokak","bu yüzden bir başlangıç hissini","yok sayıyormuşçasına","bazense yolun sonuymuşçasına","rengimden atıyorum","","bana bir gölgeyi hediye eder gibi","dağılan ve parçalanan buz tanelerinin arasında","birinin ellerinde yeniden çözülmekten bahsediyorsun","bense birkaç halinin daha olduğunu biliyorum gölgelerin","","haki bir kurşunu gizlediğini biliyorum","satır aralarına","bense bilmiyormuşçasına ilk sayfasında","bazense yara almamışçasına","gölgelerin oyununa geliyorum"]},{"id":"erimsiz-kelimeler-kulliyati-iv","title":"Erimsiz Kelimeler Külliyatı - IV","date":"3 yıl önce","type":"verse","epigraph":{"art":"Son Yargı - Michelangelo (Sistine Şapeli’nin Ünlü Tavanı)","quote":null},"body":["binlerce tanrının arasından","ah! seni yalnızca biriyle kandırmaları...","","aykırı bir sorudur artık varlığımız","hem hangi dilde dua ettiğine dikkat etmez hiçbir tanrı"],"image":"images/erimsiz-iv-michelangelo.jpg"},{"id":"erimsiz-kelimeler-kulliyati-v","title":"Erimsiz Kelimeler Külliyatı - V","date":"4 ay önce","type":"verse","epigraph":null,"body":["Şuraya imzamızı atalım.","Böylece cehenneme hoşgeldik anları...","Ne güzel... Burada da zaman ilerliyor mu peki?","İlerliyordur muhakkak. Mesela şu gördüğün güneş sistemi.","Ne? o da mı boşluk?","Bırak lafügüzaflığı. Hem Çukurova'da ona boşboşçuluk da derler.","İndirirler Allahları aşağı (Hangi aşağı onu karıştırma)","","Bu sıcakta o boşluğa gitmez hiçbir şey.","Be adam, be kadın, be cinsiyet ön eki kabul etmeyen insan!","ön eki mi dedim? Öf be kardeşim ne çok soru...","Şimdi biz güneş sisteminden çıkınca zamanı kim sayacak?","Soru orada duruyor, kim sayacak?","","Bir köy vardı geçen nah şu ileride.","Yirmi yılda bir ismi değiştiğinden olacak,","giden bulamaz bir daha eski halini.","Ee tabii, kaç yıl sonra gittiğine göre değişen bir durum.","Hangi sistemde yaşıyorsa bir tardigrade, zaman ona göredir.","Be adam, be kadın, be cinsiyet...","Oturup yirmi yılda bir algoritma mı yazdın?","","Bak imza kurumuş.","Buralar eskiden Lucifer'in dediğine göre hep tarlaymış.","Anlak diye bir yer var şimdi duydun mu hiç?","Ulan iyi ki bir hoşgeldik.","Nabız ritimlerini say saat yoksa. Güneş sistemiymiş!..","","Haydi kalkalım ayağa","Nefret ayinleri başlamak üzere ahırda.","Öyle tabii, uzay karanlık.","","Ama ahır kadar kötü kokmuyordur dünyada."]},{"id":"erimsiz-kelimeler-kulliyati-vi","title":"Erimsiz Kelimeler Külliyatı VI","date":"2 ay önce","type":"verse","epigraph":null,"body":["Henüz doğmamış yıldızlar muştulayan","bir gök düşüncesi boğulur","sessiz, uzak ama uzaklığını unutmuş bir uzak ortasında","","şehrin taş duvarlarına","bir pencereyi açık bırakarak","düşler doluyor usulca","o sırada yağmur mu sanıyor ellerim nedir","başka bir yorgun elin bıraktığı çaya uzanıyor","insan susmayı böyle böyle öğreniyor","","an, içimde açılan yollar","dipsiz, sonsuz ve tenha bir mekan mı denir buna","ki göğe bakmak neyi kurtarır insandan o ara","","sormayalım diyedir belli ki bu konuşulan","şuradaki masa, eski sandalye","cümlelere birer ayna gözlerimizle","olmayanadır geceye büyüyen gözlerimizle","","yine de uçsuz bucaksız yol oluruz öyle deme","kim bilir hangi durağa yetişiriz, hangi rüzgara, hangi sessizliğe","biz sustuğumuzda en fazla bir adım atılır","","olsun da bir adım götürsün bizi","bir bakmışsın hayallerin çıkmış piyangodan","tüm bunlar içimde açılan bir yaradır diyor öteki","öteki, koynundan vesikalık çıkarır gibi yoksul","öteki, ısınmayan ellerine bakar sisli bulvarlarda","","varsa bulursun demektir bu, belledim","bu sisli bulvarlar ondandır","yeterince göğe bakmışızdır demek bu, anladım","o saatlerden sonradır ki şehre dolar sessiz gölgeler","","şimdi biri yorgunluğuna bir dolmuş seçer","öteki, boğulur ellerinde","öteki, sustuğuna bir adım daha yaklaşır","öteki, uykusuna kiracı borçlanır bir gün daha..."]},{"id":"i-lerinin-tarihcesi","title":"İlerinin Tarihçesi","date":"1 yıl önce","type":"verse","epigraph":null,"body":["bir gölge devrilir öğleden sonra","evlerin birbirine sarıldığı sokaklar zamanı","unutulmuş bir iki bakkal poşeti günün telaşından","eylülün rüzgarında dolanır durur","","umut artık bir kelime sadece bazı saatler","-eski mektuplar da şimdi postane arşivlerindedir hala-","ne çok büyütmüşüz böyle kelimeleri oysa","ileri doğru yürür görünür sana bana","hangi görüntü ileri hangisi geri?","","bazı sokakların hafızası var orası kesin","adımını duyar duymaz yüreğinden yakalar","olmaz, bir türlü ritmik düzende gitmez adımlar","epey sonra, insan uzak kaldığı yerleri","küçük gelen yerlermişçesine adımlar","","bir cümleye son kelimeleri yazmak da çok eski","sokakların hafızasına benzer","nemli postane arşivlerine ya da","renkli sabahları unutulmuş sahil kasabası yalnızlığına","","sınırı bulmayı istemek","ilerinin ve gerinin bahçesinde","sahi, neye benzer?"]},{"id":"m-rida","title":"Mérida","date":"1 yıl önce","type":"verse","epigraph":null,"body":["sırtımda bir zıpkın Mérida","dilsiz bir acıyla gidilebildiği kadar ardımsıra","ardım dalgalar boyu kan","nereden bilsin bulutlar, onlara kızmıyorum","hem büyüyor yorgunluğum arttıkça kırmızıdan bir tablonun","acıyla büyüyen, bir öbür kırmızıdan.","","gözlerim bulanıklaşmaya başladı Mérida","duyduğumu hatırlıyorum","dudaklarının kıyısına vuran şeyleri","gör diye bakılan bir söylenceye","geçmişe yolu olmayan bir öbür söylenceden","","acı çekerek gökyüzüne bakılırmış oysa Mérida","afyonumu dudağının kıyısında","avlanırken bir avcı zihnimdekileri","denizinden ayrılmış bir martıya hazırlatmış","diyorlar","","bu sözler şimdi neresi için Mérida?","tüm bunlar nesi için bu şeylerin?","Bu şeyler bir dalgasında ıssızın","zıpkının süsü olmuş gibi kırmızıdan","sandalında dağılmış gibi","","yüzüyorlar"]},{"id":"dinozor-kebap","title":"Dinozor Kebap","date":"2 yıl önce","type":"verse","epigraph":null,"body":["Tek hücreli çağların düzensizlikerini aklımdaki","oturdum yazdım sert bir kıvrıma adarken,","elbette ömrümüzü adarken","işlevsiz bir teni oturdum yazdım…","","O çağların ifasıdır kanımdaki","-şimdilik bunu bir kenara bırakalım-","epeydir kenara bırakmıyorduk da hani","","ve dahası","anlaşılması için bir yerlerimi dağıtmam gerek","","biz biraz aceleciyiz üstelik bazı aşklara","aşklar mı diyorum? ağız alışkanlığı siz uymayın bana","yani tenini sunarken yanar parmak uçları","bu yüzden bir yerlerimi eksiltmem gerek","","Bağışla bu kadar geç gelişimi","ki bu artık adımlarımızın kayboluşuna akan","elbette ömrümüzü adarken işlevsiz kanımıza","oturup yazdığımdı…","Oturdum dediğime bakma, oturmadan da yazıyor insan","önce soluna yazıyor","ama sırası değil bunların","kaybolmanın bir bedeli yoktu belki de","yine soluna yazıyor","","Birileri bir düzen arıyor","bir kural rediflerindeki","üleştirilememişliklerin uzunluğuna aldanıyor, yazık...","biri harf koydu biri beyitsiz hayal etti ellerimizi","","bunlardan kurtulmak için bir yerlerimi dağıtmam gerek şimdi","en iyisi bizi aramayın, sessiz harfler kullanın bu kâfi"]},{"id":"ekrem-in-buyuk-harfleri","title":"Ekrem'in Büyük Harfleri","date":"3 yıl önce","type":"verse","epigraph":null,"body":["kabullenemiyorsun ya ellerine baktığında bir gerçeği","o an Ekrem’in anlında rüzgar kuşkulanıyor","Ekrem ki biraz eğridir oturunca","göğsünden fazlasıyla uzak kaldığındandır bu belki","dağılmış pazar yerleri gibidir o ara gözleri","","vardır elbet kabullenmenin de bir tarihi","hep kendiyle mi vuruşur insan sahi?","Ekrem’e sorsak bunun nedeni gereksizdir","insan en azından hayatında bir kez güzel oturmalıdır","","biçimsizleşmenin de bir tarihi vardır Ekrem’e göre","ellerine bıraktığında yansıyor yüzümüze ancak","kimse bilmiyor suya ilk düşen yıldırımın sonuçlarını","milyar yıl önce yaşanan sessizliği milad kabul ediyor Ekrem","milattan sonrası artık gereksiz bir tarih diyor.","","şimdi anlaşılıyor ekremin pazar yerleri gibi","dağılmış gözlerinde hiçbir söz neden büyük harfle başlamıyor","kendine ulaşmanın bir tarihi olduğundan bahsediyor Ekrem","çoğunlukla buna zaman yetmiyor, diyor","","Biz o sırada Ekrem’in büyük harfleriyle yan yana oturuyoruz","Hepimiz sırayla satırbaşlarından siliyoruz kendimizi"]},{"id":"basligin-biri-bir-siir-aramaya-cikmis","title":"Başlığın biri bir şiir aramaya çıkmış...","date":"3 yıl önce","type":"verse","epigraph":null,"body":["Anne merhaba, tabii ben geldim","piç edilmiş bir hüzünle geldim","geldim gelmesine de ev duygusunu bir yerlerde kaybettim","yetmiyor bu adımlar ne yaptığımı anlamaya","kısacası ben, geldiğimi varsayıyorum birkaç adımla","","Yani anne merhaba işte","noktasız virgülsüz yazmaya başlayınca anlıyor insan","\"ne yaptığımı bilmiyorum\"ları sererken balkonuna","\"ne istediğimi bilmiyorum\"ları doldururken bir su bardağına","güzel bir şey getirdim en azından bu hengamede","işte, pürüzsüz bir merhaba.","bırakalım bunlar da virgülsüz dursun","","İstersen anne, şöyle yapalım:","bir virgül daha koyalım devam etmişken yola","analog bir kalbin ortasında biriken sigara yanıklarını","yeni bir küllük diye tanıtalım gözlerimize","buradan çıkan sonuçları bir köşeye bırakalım","öykünün devamını arayan gözlerimizi","onulmaz yaralarımızın hangi analojiyle dört dörtlük uyduğunu","sanrılarımızın dağ eteklerine savuralım","","\"Mümkünatı yok bunun\"larla dizerken cümleleri anne","istersen artık büyük harflerle başlamayalım","yani merhaba anne","gerçekten bilmiyorum","taşınırken, bu kelimeleri kendim kolilere koyabilseydim keşke","üstüne bir de \"dikkat kırılacak!\" etiketi","belki daha yararlı olurdum topluma","","birkaç yaz daha geç kalmış bir merhabayım şimdi anne","işte burada, inanamazsın nasıl yönünü kaybettiğini","","Anne merhaba,","merhaba anne"]},{"id":"merhaba-cicegi","title":"Merhaba Çiçeği","date":"3 yıl önce","type":"verse","epigraph":null,"body":["Bize baktın ve haline şükrettin Asuman","almak üzerine kurulu bir ilişkiyi yüceltmiştin","bizi sevmedin, başkaydı renkler o gün","kapısı caddelere açılan evlerden uzaktın","","Şehrin parklarına suni oksijen gülleri serilmiş","zift döküyoruz göğsümüze biz de, kaldı ki","güvenlikli sitenin 44. katına taş atamaz insan","nasıl da olağan şüpheli oluyoruz o ara bir bilsen","44. kat bir hücre miydi Asuman?","","Sense yalnızlığımın kalesi derdin","hayatın boyunca Asuman,","bir daha görmeyeceğin caddelere taştı gözlerim","","Caddenin başına dikeceklerine söz verdiler","heykelimi değil Asuman, kendimi","beni bir ıhlamur ağacının gövdesine aşılayacaklar","çiçek açtığımda sana serçelerle merhabalar göndereceğim"]},{"id":"katharsis","title":"Katharsis","date":"3 yıl önce","type":"verse","epigraph":null,"body":["Birkaç ucuz ihtişamla günden kalan","harelenmiş gamzesinde biraz yorgun","bilinir mi sebebi dersin huşûyla bir tüyün","gelip gelip konması en kuytusuna büsbütün?","","Görülür mü dersin güpegündüz bir kadının","dönüp dönüp hayatı arkasında bırakılan","neşesi olan ama aslında neşesi olmayan","durup durup kırılması en derininden aynasının?","","Bunları geçelim şimdilik Faust’un orkestrasından","iyisi mi, payımıza sol major albay Buendia’dan","anlaşılır mı dersin geçmişine çekilen süngerin","belli belirsiz izleri çocukluğumuzun kapısından?"]},{"id":"oglum-ulvi","title":"Oğlum Ulvi!","date":"3 yıl önce","type":"verse","epigraph":null,"body":["Oğlum Ulvi! Gözlerini getirmediğini neden anlatıyorsun?","konuşuyor işte sıfatın, kelimeler hep ağzımızdan mı çıkar sandın?","bak bazı kelimeler öyle çığırtkandır ki adımlarından önce oradadır","bazıları seni öylece ele verir","","Muhbirdir oğlum bazıları yüz çehrende","her an seni ele vermek için tetiktedir","çorba içerken de konuşursun yani","ekmeği koparırken ya da tuz serperken","ihtişamlı bir ünlem gibi durur ellerin bazen Ulvi.","sen bunu çoğu zaman unutursun","","Oğlum Ulvi! Başım artık daha çok ağrıyor","şakaklarıma götürdüğüm ellerimden","bıraktığım izlerden anlıyorsundur bunu","seninle biz artık pek konuşmuyoruz biliyorsun","sen aynalara küstüğünden beri kimse içtenlikle tütün içmiyor.","","Oğlum Ulvi! Biri sokak köpeğine çarpıp kaçmış","artık başım çatlıyor."]}]},{"id":"oykuler","name":"Öyküler","pieces":[{"id":"mephisto-nun-yeri","title":"Mephisto'nun Yeri","date":"3 yıl önce","type":"prose","epigraph":{"art":"Alexandre Cabanel – Düşmüş Melek","quote":"Tanrı'yı gerçekten tanısaydın Dante, sen de isyan ederdin."},"body":["İçeri girdiğimde Mephisto, iki metre beyaz kanatlarıyla, arkası dönük, bar taburesinin üstünde içkisini yudumluyordu. Evet, evet! Yanılmıyordum. İki metre beyaz kanatlarıyla oradaydı! Bu yüzden hiç kimse yanına oturmak bir yana, barmenden dahi bir şey isteyemiyordu. O sırada elindeki Martini'den boşta kalan sağ baş parmağını belli aralıklarla bardağının kenarına ağır ağır tıklatıp duruyordu. Hiçbirimiz alışık değildik böyle çat kapı bir meleğin bara gelip demlenmesine. Arkası dönük olduğu halde her birimizin adını, nereye baktığımızı ve ne düşündüğümüzü en ince ayrıntısına kadar görebiliyor oluşu ayrı bir kaostu.","","Önce bar masasına gitmeyi düşünmüştüm fakat saliseler içinde bu fikrimden vazgeçip gerisin geri barın tenha bir yerini gözüme kestirmiştim. Bana seslendiğini anladığım o an kafama dank etmişti içimden geçenleri bildiğini. Ama artık geç kalmıştım. Sağ kanadını çoktan toparlamış, bana yer açmıştı. Yapacak bir şey yoktu. Bar taburesine otururken parmağıyla çıkardığı tıkırdama sesleri artık durmuştu. Ne bana bakıyor, ne de bir şey söylüyordu barmenin tedirgin bakışları arasında. Martini'sinden bir yudum daha aldıktan sonra \"Neden?\" diye soruyordu o tok ve megafonvari sesiyle. O sırada barmen, korkudan yanıma gelip ne istediğimi bile soramamış, ben de öylece bir kaktüs gibi kalakalmıştım. Cevap veremediğim her saniye gerilimi gittikçe arttırıyor, bir türlü karşılık veremiyordum bu soruya. Bu, tıpkı tüm varyantları bilen birine karşı umutsuzca bir meydan okumaya benziyordu bir satranç tahtasında. \"Ne söyleyeceğimi biliyorsun Mephisto, neden bizimle...\" Bu cümleyi o an neden ve nasıl kurduğumu anlayamamıştım ki sözümü kesti: \"Evet neden sizinle böyle oyunlar oynuyorum değil mi?\" dedi eğlenceli bir ses tonuyla.","\"Bak dostum, bak! Etrafına iyice bir bak. Burası benim cehennemimi de sollamış. Hahaha! Artık varoluşunuz sonlandığında eskisi kadar korkmanıza gerek kalmadı.\" İçkisinden bir yudum daha alarak, cebinden çıkardığı sarma tütünü nefesiyle küçük bir alev topuna dönüştürdü o sırada. \"Hay aksi! Çabuk bitti. Dostum sağ iç cebindeki puroyu paylaşmak ister misin?\" diye sordu alaycı bir gülümsemeyle.","","Alışmıştım artık her şeyi biliyor oluşuna. Zaten çok çabuk alışıyorduk her şeye. Buna da şaşmamalı. \"Evet, işte en çok bu yaralıyor beni, mi amor!\" diye ekledi bu düşüncemin bir kaç saniye arkasından. Sanki delirmiştim ve artık şizofreninin geri dönülemez evresindeydim o an. Puroyu verirken yine belleğimi yoklamıştı: \" Estoy muy cansada pero tengo una cosa muy divertida, hahaha.\" Belleğimdekilerle oynadığı oyuna aldırmamaya çalışarak bir bira istedim barmenden. Bir an önce bir iki kadeh içip rahatlamış olarak eve gitmekten başka bir isteğim yoktu artık. Aslında bara ilk girdiğim anda gördüğüm bu gariplik karşısında hemen dışarı çıkmak daha doğruydu diye iç geçirmiştim ki, bir an zihnimin okunabildiği gerçeği Mephisto'nun o alaycı gülümsemesinde çoktan belirmişti. \"Dostum, bu yabancı kelimeler, yani her dilde yabancısı olduğum bu kelimeler, yani birbirinizi bana gerek kalmadan kafeslediğiniz bu kelimeler yok mu...\" bir an duraksadı. \"Hayır baba, kimseyi korkutmuyorum! Onlar zaten kendilerinden yeterince korkuyorlar! Ben artık buradayım. Bırak yakamı!\"","","Sesinin şiddeti hemen yanımdaki camı titretmeye yetmişti. Artık gitmeliydim. Buna daha fazla dayanamıyordum. \"Ben de dostum, artık ben de dayanamıyorum tüm bunlara.\" dedikten sonra bir anda ortadan kaybolmuş ortalık esrarengiz bir sessizliğe bürünmüştü. Bu olaydan sonra artık hiç kimse eskisi gibi davranamamış, dondurulmuş bir film karesini andıran bir görüntü gibi her şey o an zamandan soyutlanmıştı. Bense daha bir heyecanlanmıştım. Fakat o günden sonra Mephisto bize bir daha hiç görünmedi. Hem neden görünmek istesindi? Buralar, gerçekten de söylediği kadar vardı.","","Biz mi ölmüştük yoksa o mu buraya gelmişti? Şimdi eve giderken tenimdeki ürpertiden çok, bu soru ağır basıyordu."],"image":"images/mephisto-i-cabanel.jpg"},{"id":"mephisto-nun-yeri-ii-zamanin-kiyisinda","title":"Mephisto'nun Yeri - II (Zamanın Kıyısında)","date":"1 ay önce","type":"prose","epigraph":{"art":"The Anxious Journey - Giorgio de Chirico, 1913","quote":null},"body":["...Eve giderken düşünceler beynimde dönüp duruyordu. Mephisto gerçekten orada mıydı, yoksa bu olanlar yorgun zihnimin bir oyunu muydu? Tenimdeki ürperti, omurgamdan yukarı doğru çıkan bir elektrik dalgası gibi tüm bedenimi esir almıştı. Ama hayır, bu sadece bir yanılsama olamazdı. Sesini duymuştum, kanatlarının gölgesi bar boyunca uzanmıştı. Kendi içimde gidip gelen bir savaşın ortasındaydım.","","Kapıyı açtım. Evin sessizliği, sanki az önce yaşadıklarımı teyit eder gibi üzerime çöktü. Işığı açmadan koltuğa oturdum. Düşüncelerim beni bir girdap gibi içine çekiyordu. \"Biz mi ölmüştük?\" diye sormuştum kendime. Bu soru, Mephisto'nun o tok sesinin yankısıyla zihnimde bir kez daha yankılandı. \"Siz zaten kendinizden korkuyorsunuz...\"","","Ne demek istemişti? İnsan, kendinden korkar mıydı? Cevabı biliyordum ama kabul etmek istemiyordum. Bu dünyada her şey, hayatta kalma refleksi üzerine kurulu değil miydi? Varoluşun dayanılmaz ağırlığı altında ezilirken, insan en çok kendi zihniyle savaşmıyor muydu?","","Sonra bir şey dikkatimi çekti. Oturma odasının ortasında, daha önce hiç fark etmediğim küçük bir zarf duruyordu. İçimden bir ses, bunun Mephisto'yla bağlantılı olduğunu söylüyordu. Yerimden kalktım ve zarfa doğru ilerledim. Parmaklarım, zarfı tutarken titriyordu. Yoksa bu bir tuzak mıydı?..","","Zarfı açtığımda içinden tek bir kelime çıktı: \"SEÇ.\"","","Bu kadar mıydı? Peki neyi seçmem gerekiyordu? Zihnim daha da bulanıklaştı. O sırada salonun karanlığında, çok hafif bir gülüş yankılandı. Mephisto'nun sesiydi bu. \"Dostum, bir cevap arıyorsan... kendine dönüp bak.\"","","Bir an için nefesim kesildi. Sanki evin dört bir yanı o kanatların gölgesiyle dolmuştu. Ama onu göremiyordum. Karanlık, sadece bir fısıltı ve o uğursuz varlık. \"Bu kadar kolay değil,\" dedi ses. \"Seçimini yapmadan huzura eremezsin.\"","","Bir anda her şey sustu. Kalbim deli gibi atıyordu. Ellerim hâlâ zarfta yazan kelimeyi sıkıca tutuyordu. Seçim mi? Neyin seçimi? Evdeki sessizlik, artık dayanılmaz bir yük haline gelmişti. Daha fazla dayanamayarak pencereye koştum.","","Gecenin karanlığında bir gölge belirdi. Bu kez tamamen net bir şekilde gördüm. Kanatları yoktu ama gözlerindeki derinlik, ruhumu bir ayna gibi yansıtıyordu. \"Ben zaten hep buradaydım,\" dedi. \"Asıl soru şu: Sen, neredesin?\"","","Bu kez cevap bendeydi. Ama ne olduğunu bilmiyordum...","","Dipnot: Çoktandır yazıp paylaşamadığım bu öykünün devamı olan \"Seçim Kapısı\" biter bitmez burada paylaşmayı umuyorum. Sevgiler..."],"image":"images/mephisto-ii-de-chirico.jpg"},{"id":"mephisto-nun-yeri-iii-secim-kapisi","title":"Mephisto'nun Yeri - III ( Seçim Kapısı)","date":"1 ay önce","type":"prose","epigraph":{"art":"René Magritte, La Victoire, 2010","quote":null},"body":["“…Pencerede gördüğüm o gölge artık ortalıkta yoktu. Ama bıraktığı izler, zihnimde derin bir oyuk açmış gibiydi. \"Sen, neredesin?\"","Zarfı hâlâ sıkıca tutuyordum. Sanki elimde tuttuğum o küçük kağıt parçası, cevabını bilmediğim bir bilmecenin anahtarıydı. Koltuğa geri oturdum. Etrafımdaki sessizlik bir ağ gibi üzerime çökmüştü. O an fark ettim ki artık buradan kaçamazdım. Bu, bir barda yaşadığım tuhaf bir karşılaşma değildi artık. Bu, beni derinlere çeken bir çağrıydı.","Bir şey yapmalıydım. Ama ne? Zarfı dikkatlice yeniden inceledim. Sadece tek bir kelime yazıyordu: \"SEÇ.\" Bu kadar yalın, bu kadar belirsiz…","Zihnimde yankılanan Mephisto'nun sesi bir kez daha beni harekete geçirdi: \"Kendine dönüp bak.\" Kendime dönüp bakmak... Bu, insanın en zor yaptığı şey değil miydi? Geçmişte yaptığım hataları, korkularımı, kendime itiraf edemediğim gerçekleri düşündükçe zaman ve mekan duygumu kaybetmek üzereydim.","Soluk aldım ve gözlerimi kapadım. Bir an için tüm dünya sustu. Zihnimde tuhaf bir kapı belirdi. Eski, ağır ve demirden bir kapı. Yıllardır açılmayı bekliyordu sanki. Kapıya doğru ilerledim.","Kapıya yaklaştıkça üzerindeki semboller belirginleşti: hayatımdaki dönüm noktalarını temsil eden şekiller; bir çocuk eli, kırık bir saat, bir kalp, bir ayna… Hepsi bana ait anılardı. Kapının tokmağına dokunduğum anda Mephisto'nun o tok sesi yankılandı: \"Hazır mısın? Bu kapıyı açmanın geri dönüşü yok.\"","Hazır mıydım? Bunun ne anlama geldiğini bilmiyordum ama içimde bir şey, bunun kaçınılmaz olduğunu söylüyordu. Tokmağı çevirdim ve kapıyı araladım.","Kapının ardında, göz alabildiğine beyaz bir boşluk vardı. İlk adımımı attığımda anılarım bir film şeridi gibi gözümün önünden geçmeye başladı. Her biri bana bir şey söylüyor, her biri beni bir seçimle yüzleştiriyordu.","Çocukluğumdan bir sahne belirdi. Küçük bir çocuk olarak köşeye sinmiş, elimde kırık bir oyuncakla ağlıyordum. Bir ses fısıldadı: \"Bunu neden hatırlıyorsun? Kırık oyuncak mıydı seni üzen, yoksa kimsenin seni fark etmemesi mi?\"","Bir sonraki sahnede gençliğime gittim. Bir arkadaşıma sırtımı dönmüş, kendi çıkarlarım için onu yalnız bırakmıştım. O an içim parçalanmıştı. Mephisto'nun sesi bir kez daha yankılandı: \"Herkes kendi cehenneminin oduncusudur, dostum. Senin cehennemin nedir?\"","Adım attıkça, karşıma kapılar çıkıyordu. Her iki kapının ortasında sorular vardı:  Sevgi mi, özgürlük mü? Onur mu, gurur mu? Gerçek mi, huzur mu? Hepsinde biraz duraksıyor, hepsinde vermek üzere olduğum cevaplarla mücadele ediyordum.","Sonunda bir kapı daha belirdi. Üzerinde sadece bir kelime vardı: \"VARLIK.\" Anlamını tam çözemedim ama bu kapıya yöneldim. Tokmağı çevirdiğim anda Mephisto'nun sesi bir kez daha kulaklarımı doldurdu:","\"Şimdi anladın mı? Cehenneminin sınırları yok. Senin seçimlerin, senin varoluşun. Peki, şimdi ne yapacaksın?\"","Kapının ardında, kendimi gördüm. Gözlerimin içine baktığım o an, her şey anlaşıldı. Ben, kendi hapishanemin gardiyanıydım. Mephisto'nun oyunları, sadece beni kendi yüzleşmemle baş başa bırakmak içindi.","O anda her şeyin bir anlamı olduğunu fark etmeye başlamıştım. Gözlerimi açtığımda oturma odamdaydım. Zarf masanın üzerinde duruyordu. Ama artık bir fark vardı. \"SEÇ\" kelimesinin altına bir şeyler daha eklenmişti: \"YAŞA.\"","Mephisto bir daha bana görünmedi. Onun bıraktığı iz, tüm hayatımın dönüm noktasıyla eşdeğerdi. Çünkü artık biliyordum ki her seçim varoluşun bir parçasıydı ve korkmaktan vazgeçmek, ilk adımı atmaktı…”"],"image":"images/mephisto-iii-magritte.jpg"},{"id":"kulup","title":"Kulüp","date":"3 yıl önce","type":"prose","epigraph":null,"body":["“…","- Şimdi biz bu piyonu oynarsak hamle yine bizde.","- Nasıl yani?","- Ona zorunlu hamle yaptırmış olacağımız için yapacağı hamleyi tahmin etmek zor değil. O yüzden hamle hep bizde.","- Peki ya sonra?","- Sonra bir hamle daha yaptıktan sonra, hamle sırası bir kez daha bizde.","- Yine mi?","- Evet, yine! Ne yani, ona istediği hamleyi yapma fırsatı mı vermek istiyorsun Max?","- En azından karşılıklı oynarız diye düşünmüştüm…","- Evet, karşılıklı oynuyorsunuz tabii. Bir sen hamle yapıyorsun, bir o. Ama ipler senin elinde olmalı. Hem sen kazanmak istemiyor musun bu oyunu?","- Elbette ama bu sadece benim istediğim şekilde bir minyatür olacaksa pek de bir eğlencesi kalmıyor gibi.","- O halde satrancı bırak Max! Zamanını bu kulüpte boşa harcıyorsun.","- Tamam tamam. Kızma hemen. Şu bahsettiğin zayıf kareler sanki bu oyunda da var Greg. Bak mesela, c6 ve d5 kareleri zayıf. Öyle değil mi?","- Öyle gözüküyor ama onun karşılığında senden istediği şeyler var: Oraya harcayacağın zaman ve oraya yönlendireceğin taşların… Böylece yeterince zaman kazanmış olacak ve beraberliği garantileyip rehavete kapılacak rakibin. Oynarken bu duyguya ilk kapılan, varyantları pek önemsemez ve kaybeder.","- Greg?","- Efendim Max?","- Yaşadığımız dünya da böyle mi sence?","- Daha da kötü bir yer. Ama büyüdüğünde o lekeyi taşımaya alışmış olacağın için pek anlamayabilirsin. Hamle yapmak zorunda kalacaksın. Sonra bir hamle daha... İplerin senin elinde olduğunu sanarak rehavete kapılmaya başladığında sana hazırlanmış olan sürpriz varyantı keşfetmiş olacaksın. Bunu keşfettiğinde isteyerek seçmediğin bu varyantta oyunu uzatacak hamleler aramaya başlayacaksın. Sonunda kazananın kim olduğunu söylememe gerek yok herhalde?","- Bana o yüzden bu oyunu öğretiyorsun değil mi?","- Hayır Max! Sen öğrenmeyi istediğin için öğretmeye çalışıyorum. Gördüğün gibi, burası bir satranç kulübü ve sen de her hafta buraya gelmeyi tercih ediyorsun. Ama seni anlıyorum küçük dostum, bazen irademizin bize neler yapacağını kestirmek gerçekten zor. Haydi bakalım bugünkü çalışmamız bu kadar. Haftaya devam edelim bahsettiğim zayıf karelerden olur mu?","- Olur Greg. Şimdi gitmeliyim öyleyse. Haftaya görüşürüz!","","Max tüm bu zayıf karelerin hayatta da var olabileceğini düşünmeye başladı kulüpten ayrılırken. “Zayıf kareler, tıpkı insanların bu dünyada sahip oldukları veya olduklarını sandığı zayıflıklar... Dünya ne tuhaf bir yer! Neydi bu zayıflıklarla alıp veremediği bu insanların?”","","O sırada karşıdan karşıya geçmekte olduğunun yeni farkındaydı Max. Bir araba hızla geçip sinirli kornasını ardı ardına çalarken rüzgarını sertçe savurdu önünden. Yürürken birden ıslaklığını hissetti paçalarından ayak bileklerine doğru akan hafif çamurumsu sıvının. “Gerçekten de dünya kötü sürprizlerle dolu,” diye düşündü. Her şey sürekli bir sürpriz halinde olmak zorunda mıydı? Anlamlandırmak zordu şimdilik.","","Adımlarını sıklaştırdı, hava kararıyordu. Akşam yemeğine yetişememesi, ikinci kötü sürpriz olasılığını arttırıyordu…”","","*Kulüp adlı taslağımdan ufak bir bölümdür. Belki tamamlayamayabilirim bu çalışmayı. Ya da tembellik hakkımı kullanıp bırakırım."]}]},{"id":"denemeler","name":"Denemeler","pieces":[{"id":"domates-surat","title":"Domates Surat","date":"3 yıl önce","type":"prose","epigraph":null,"body":["Bugün bir karasineği kurtardım pencere önünden. Oysa çocukken bu küçük yaratıkları yakalayıp kanatlarıyla oynamaya çalışır, onlara daha yakından bakayım derken gözlerimin ağrıdığını hissederdim. Hatta bir keresinde çizgi filmlerden etkilenip bir kaplumbağanın içinde neler var diye merak salmış, kabuğunu o an -merakıma yenik düşerek- çaresizce kırmaya çalışmıştım. Yetmemiş, yine kedilerin gerçekten sürekli dört ayak üstüne düşüp düşmediğini anlamak için ikinci katın balkonundan biraz sonra neler olacağından habersiz bir kediyi aşağıya bırakmıştım. Kedi gerçekten de dört ayak üstüne düşünce hayretler içinde kalakalmıştım. Üstelik aşağı düşer düşmez hiçbir şey olmamış gibi bir gelincik edasıyla hızla oradan oraya sekerek ortadan kaybolmuştu. Tabii, bunları yaparken ortalığı iyice kolaçan etmiş, birinin görme ihtimalini en aza indirecek saatleri seçmiştim. Yine de o an oradan geçen yaşıtım bir kızın çığlıklarından kaçamamış, büyük bir suçluluk duygusuyla domates suratlı birine dönüşmüştüm artık. Kızarmış yanaklarımı biraz daha sıksam, yanan suratım patlayacakmış gibi olurdu o an sanki.","","Daha sonraları, aklı başında biri olarak, babamın kütüphanesindeki ansiklopedilere dadanmıştım. Artık burada merak ettiğim şeyler hakkında riske girmeden, zaman kaybetmeden ve domates suratlı birine dönüşmeden çoğu şeyi öğrenecektim. Bu ansiklopedilerin arka sayfalarında veya ön sayfalarındaki dizinler benim için bir \"google search\" görevi görüyordu o zamanlar. Aradığım anahtar kelimeler sayfalarıyla beraber bu dizinlerde bulunurdu. Bu aynı zamanda epey bir zaman kaybı demekti. Yine de arayıp bulabilmenin, ararken farklı bilgilere denk gelmenin verdiği heyecan buna değerdi. Mesela, Afrika kıtasında yaşayan bir kabileyi ararken gözüm başka bir sayfada ilgimi çeken, bir kuşa göre iri cüsseli, pençeleri daha önce hiç görülmemiş kadar geniş, uzun bacaklı ve tuhaf kuyruklu tüyüyle nesli artık tükenmiş \"Arkeopteriks\"lere kayardı. Bu benim için yeterince heyecan vericiydi. Tarih öncesi dönemlerde yaşamak ne kadar heyecan vericidir kim bilir, diye düşünür hayaller kurardım. Kısacası kendime bir dünya yaratmaya başlamıştım babamın kitapları arasında. Neler yoktu ki içinde! Yan yana gelmiş bir sürü sessiz harfleri olan yabancı yazarların yazmış olduğu öyküler, şiirler, romanlar, resimli sözlükler, büyük ve ayrıntılı atlaslar, hatta o zamanlar hiç anlam veremediğim psikoloji kitapları; daha rahat anlayabildiğim yerli yazarların, şairlerin kitapları ve oldukça sararmış, saman kağıdına basılı aylık veya üç ayda bir çıkan dergiler de bu dünyanın içindeydi.","","Tüm bunları bana bir karasineğin hatırlatmış olmasını düşünüyorum şimdi aynı pencerenin önünde. \"Bilmek için bazen kötülüğü seçmek zorundayız.\" diyorum o an kendime. \"Zaten bilmeyi istemenin temel dürtüsü meraksa insan zarar verebilendir çevresine. 15. yüzyılla başlayan coğrafi keşifleri bugünün değerleriyle ele alırsak, kötülüğün merkezine koymak zorundayız o günkü kendimizi. Savunmasız İnka'ların Pizarro tarafından acımasızca yok edilişleri mesela...\" neyse ki kapı çalıyor o ara ve yaşadığım ana geri gönderiliyorum kapı sesiyle.","","Her neyse... Karasineğin bana hediyesi buydu belki de: Hayatını kurtarmam karşılığında bir çocuğun bir zamanlar domates suratlı halini hatırlatması."]},{"id":"mevsimsiz-sovalyeyle-la-boh-me","title":"Mevsimsiz Şövalyeyle La Bohème","date":"3 yıl önce","type":"prose","epigraph":{"art":"[Cornelis Lieste (1817-1861), Sunlit Landscape]","quote":null},"body":["Tek başınalığın verdiği huzursuzluğun tarihini anlatmakla geçiyor ömrümüz sevgilim. Artan oranda azalan bir birliktelik duygusunu sanayi devrimine borçlu olarak birçok şey dolduruldu ceplerimize.","","Yarın güneş patlamayacakmış gibi güne uyanıyoruz, nasıl da hayret… Beni en çok bu yaralıyor. Yani yarın sana en güçlü olduğum yanlarımı göstermek zorundayım sevgilim. Sense zayıflıkları tanrısal bir gülümsemeyle geçiştirmeyi seçiyorsun, ne güzel. Kendimden bir tane daha olsa onunla yapamam diyorsun. Ne garip... Gittiğimiz yerde palazlanıyorken cehennemimiz üstelik...","","Hem ortada bir mutluluk varsa bu en çok mutsuzlar sayesindedir belki. Kalabalık, böyle bir düşünceyi zehirli buluyor şimdilik. Geçelim…","","Diyorum ki, bu tek başınalığın verdiği huzursuzluktur artık. Cinsel boşalım peşinde koşan yığınlar -tek başınalıklarından kaçmayı deneyenler yani- ayıldıktan sonra ilk birleşmelerinin ardından daha büyük bir ayrı olma duygusuna kapılmalarını anlamakta zorlanıyor. Yine bir mantar kültürü besleniyor o ara, yayılıyor cehennemlerinin palazlandığı yerlerde, ne garip...","","Güneş demiştik sahi... Yalnızca sekiz dakika kırk dört saniye içinde dünyayı aydınlatıyor şu ateş topu. Yok oluştan önce kalan zamanımız belki...","","Açıkçası, acımasız umutlar saçan şairler gibi olmayı bıraktım. Bakma bana öyle. Kötü şeylerden bahsetmiyorum. Bunlar güçlü yanlarımız. Şimdi otur yanıma, yarın patlayacakmış gibi güneş birbirimize bakalım.","","Yanisi şu sevgilim: Sevgi, sanıldığının aksine öğrenilebilir bir şey. Sınavı da uzun sürer diyorlar. Sevmek için bir şeyleri bilmek gerekir. Bir şeyleri anlamak için bir şeyleri yapmak gerekir diyorlar.","","Demek ki anlayabildiğimiz kadar seveceğiz birbirimizi bize kalan sekiz dakika kırk dört saniyede. Epeydir katran sarmış bu arada ciğerlerimi. Bense iki nokta altı milyar insanın açlığına öksürüyorum.","","Yanisi şu ki, Emile Zola’nın yağmalanmış Paris’ini çiziyorum sigara külleriyle avuçlarıma ve çoğu zaman katranı yok sayıyorum. Hatta bazen Nilgün Marmara’nın oturduğu merdivenler oluyorum kül tablasını uzattığın o ara. Yine de bir ederi yok diyorlar artık bunların. Geçelim.","","Nesneleştirdiğim çoğu \"şey\" kadar sahiplik eki fırlatıyorum penceremden. İlerleme haline aldanmış kobay fareleri gibi bakışıyoruz o esnada. Nasıl olsa hep ilerleme duygusuna bürünmüş çoğu asfalt. İzin ver, ilerisi için izah edeyim:","","Şöyle ki sevgilim, beni bir kınsız şövalye olarak değirmenlerine bırak arayışların. Vazgeçerken dahi son kez vuruşayım..."],"image":"images/mevsimsiz-sovalyeyle-lieste.jpg"},{"id":"artik-sokaga-cikabilirsin","title":"Artık Sokağa Çıkabilirsin","date":"3 yıl önce","type":"prose","epigraph":null,"body":["Onca yokluk içinde anlıma doğrulttuğum tükenmez kalemin silgisiz kelimelerin kalibresini arttırdığını seninle oynadığımız o tehlikeli oyunlardan sonra anladım. Tamahkâr bir yarının ellerimizle yaratıldığı o günü, kelimelerden etrafa yayılan saçmalarla kurtarmaya çalıştığımı yazık ki çok geç fark edeceksin. Hoş, işbu anlaşmanın tüm maddelerini -geriye dönük olmayanlarını- çoktan buruşturup herhangi bir çöp tenekesine bırakmış olacağım. Acılarım hükümsüzdür.","","Madde 1.","İrade Açıklaması","Momo'ya söz verdim. Kalbi atıyor hâlâ çalışma masamın çekmecesinde çünkü. O yüzden dizlerimde biriken kan pıhtılarını gördüğünde dehşete düşmeni normal karşılıyorum şimdilik.","","1-A Sherwood ormanına git. Orada gördüğün en yaşlı ağacın dibine otur. En yaşlı ağacı bulana kadar böylece zaman geçmiş, hava kararmış olacak.","","2-A Hayatta kalanları görebilmeleri için bir sigara yakmalısın. Yoksa seni kimse fark edemez.","2-b Seni almaya kimse gelmediyse, artık sigaranı söndürebilirsin. Çünkü artık onlar da büyük ihtimalle hayatta değil.","2-b Gelirlerse şayet Momo'ya söz verdiğimi anlat onlara.","2-b Bu anlaşmanın kapsadığı tüm maddeler -ileriye dönük olarak- yamalı zamanları olan modern insanların saçmalıklarıyla ilgilenmemektedir.","","3-A İşbu metne sadık kalınarak irade açıklamasının 1-A bölümü kişinin sorumluluğuna aittir.","","Madde 2.","1-A Artık sokağa çıkabilirsin. Ömrünün en güzel yıllarını bir videoyu hızlı oynatır gibi geçtin.","","Taraflar","İmza"]},{"id":"bana-kalan","title":"Bana Kalan","date":"3 yıl önce","type":"prose","epigraph":null,"body":["Parmaklarımı hissetmiyorum, birkaç yıldır da uykusuzum sevgili Mathilda.","","Tarifsiz bir boşluk içimdeki.","Gizemli incelikleriyle kalbimi yoklayan.","","Yaşlı bir şaman gözlerime bakarken düşüyor anlamsızlığı bir köşeye saatlerin ve kapı kollarının ve dahi artık hissedemediğim parmak uçlarımdaki şuursuzluğumun…","Soruluyor bir yerlerde bazı sorular, bazı yerlerde cevaplanıyor bazı sorular. Bazı sorular bazı cevapları sürekli karşılıyor sevgili Mathilda.","","Aklımın bir köşesinde hediye edilmiş bir kara deliği aldım, önüme koydum bugün. Bilinemezin sonsuzluğa uzanıp gitmesi gibiydi. Evet önümüzdeydi, sadece bakıyorduk hep beraber. Oysa görebilmeyi ne çok isterdim Mathilda.","Yani bir akşamı da kalbimde hiç ettim. Oturup parklarda köpeklerle konuştum sonra. Bir sigara yakmayı düşündüm o an -her zamanki gibi düşündüm- fakat yanıyordu her yer Mathilda. Yanıyorduk o incelikli halimizle sokak lambalarının altında. Ben, çocuk parkındakiler ve köpekleriyle birkaç cadde daha… Kıvrılıp gidiyor başka evlerin başka sokaklarına cümlelerimiz o an orada.","","Bir çocuğun unutulmuş gözlerini koydum önüme sonra. Anlamsız saatlerin ve kapı kollarının boşluğunda baktık birbirimize hissedemediğim parmak uçlarımla. Bir otel odasında göğüs kafesimi yoklamak gibi bir şey... Yani mesela ansızın bir yerlere gitme isteği…","","Sahi sormayacak mısın yorgunluğumu Mathilda? Ansızın yerleşen alnımın orta yerine, bir başınalığımı? Açıkçası önümde iki kedi yavrusu, parmak uçlarımda tüten bir kara delik ve hediye edilmiş bir bilinmezliğin ortasında ben bir şeyler aradım durdum. Sahi neden arıyorduk biz mesela?","","Boş verelim beyler bayanlar, kaçıncı mevkide olduğumuzun bir önemi var mı? Muhakkak bir limanı vardır herkesin en sonunda hep beraber ayak bastığı…"]}]},{"id":"ceviriler","name":"Çeviriler","pieces":[{"id":"kalbindeki-migfer","title":"Kalbindeki Miğfer","source":"Mario Benedetti","date":"3 yıl önce","type":"translation","note":["Bir ara kıyıda köşede kalmış (!) aşk şiirlerini derlemeye koyulmuştum. Latin Amerika'nın en sevilen şairlerinden Mario Benedetti'nin \"Corazón Coraza\"(Zırhlı Kalp) adlı şiirini çevirmeye uğraşıyordum İspanyolcadan. Çevirirken metnin dokusunu parça parça edip yapısökümcüleri haklı çıkarıyordum sanki. Fakat böyle bir yorumun da olması gerektiğini düşünmeden edemiyordum. Başlığı doğrudan çevirdiğimde \"zırhlı kalp\" anlamı ortaya çıkıyordu fakat şiirin metinsel bütünlüğü sayesinde \"Kalbindeki Miğfer\" olarak da çevirebildiğimi fark ettim.","İspanyolcada porque, “çünkü” demek ve çağrışımsal bir kelime. por qué olarak ayrı yazıldığında ise \"neden\" sorusuna dönüşebiliyor büyülü bir şekilde. Şiirin bu kelimeyle kurduğu iskelet gerçekten harika. Türkçeye çevirmek isteyince tabii çok daha büyük bir ustalık gerektiriyor bu iskeleti kurmak açısından. Elimden geldiği kadar şiirin bütünselliğini korumaya çalışsam da bir yerde her çeviri, şiirin özgünlüğünü elinden almak zorunda. Bu yüzden çevirinin aslında bir yanılsama olduğunu her seferinde bu şiirler sayesinde öğrenmeye devam ediyorum. Bu kadar gevezelikten sonra sizi şiirle baş başa bırakma zamanı gelmiştir diye düşünüyorum. Keyifli okumalar!"],"tr":["Çünkü varla yok arası","çünkü seni düşünüyorum","çünkü gece geçiyor ve ben senden bahsediyorum","çünkü resimlerini almaya geldin, tüm bu resimlerden daha iyi halinle","güzelliğinin ölçüsü yok, belki tırnakla ruh arasında bir yerde","küçük ve iyi huylu gururuyla","kalbindeki miğferinle","çünkü benimsin","çünkü benim değilsin","çünkü sana bakıyorum ve azalıyorum baktıkça","ölmekten daha kötüsü, sana bakamamak","sevememek seni yakınımda","","Çünkü istediğin yerde hayat kurabilirsin","oysa yalnızca seni sevdiğim yerler hayat verir sana","çünkü ağzın kan revan","ve hissettin çaresizliği","sevmek zorundayım seni,","sevmeliyim seni","","Bu yara bir kez daha kanatsa bile","arayıp da bulamasam bile seni","ve gece geçse de üzerimizden","sen varsın,","kim bilir belki de yoksun yanımda"],"orig":{"lang":"es","title":"Corazón coraza","author":"Mario Benedetti","body":["Porque te tengo y no","porque te pienso","porque la noche está de ojos abiertos","porque la noche pasa y digo amor","porque has venido a recoger tu imagen","y eres mejor que todas tus imágenes","porque eres linda desde el pie hasta el alma","porque eres buena desde el alma a mí","porque te escondes dulce en el orgullo","pequeña y dulce","corazón coraza","porque eres mía","porque no eres mía","porque te miro y muero","y peor que muero","si no te miro amor","si no te miro","porque tú siempre existes dondequiera","pero existes mejor donde te quiero","porque tu boca es sangre","y tienes frío","tengo que amarte amor","tengo que amarte","aunque esta herida duela como dos","aunque te busque y no te encuentre","y aunque","la noche pase y yo te tenga","y no."]},"image":"images/kalbindeki-migfer.jpg"},{"id":"18-sone","title":"18. Sone","subtitle":"Ne mümkün seni bir yaz günüyle kıyaslamak","source":"William Shakespeare","date":"3 yıl önce","type":"translation","note":["(Türkçeleştirmeye çalıştığım bir William Shakespeare şiiri.)"],"tr":["Ne mümkün seni bir yaz günüyle kıyaslamak","Ki fazlasıyla güzel ve cana yakınsın.","Sert rüzgarlarıyla mayıs taze tomurcuklarını savururken","Bir günlüğüne kiralanmış gibidir oysa yaz.","Cennetin gözüdür bazen parlayan oldukça sıcak","Ve soluk ten rengiyle çoğu zaman orada","Ve dahi her güzelliğin yaklaştığı bir son gibi","Kaderin yahut doğanın kucağında.","Oysa solmayacak sendeki ölümsüz yaz","Asla bitmez sevgi, yüreğindeki","Övünemez ölüm, gölgesiyle dolaşırken","Sonsuz akışında yol aldığımız bu zaman diliminde üstelik.","Kaldığı sürece bu can bu bedende, görebildiği sürece bu göz","Yaşadıkça bu yazdıklarım, sana hayat vermeye devam etmeli."],"orig":{"lang":"en","title":"Sonnet 18","subtitle":"Shall I compare thee to a summer’s day?","author":"William Shakespeare","body":["Shall I compare thee to a summer’s day?","Thou art more lovely and more temperate:","Rough winds do shake the darling buds of May,","And summer’s lease hath all too short a date;","Sometime too hot the eye of heaven shines,","And often is his gold complexion dimm'd;","And every fair from fair sometime declines,","By chance or nature’s changing course untrimm'd;","But thy eternal summer shall not fade,","Nor lose possession of that fair thou ow’st;","Nor shall death brag thou wander’st in his shade,","When in eternal lines to time thou grow’st:","   So long as men can breathe or eyes can see,","   So long lives this, and this gives life to thee."]}},{"id":"sevmek-bilincini","title":"Sevmek, bilincini kaybedene dek","source":"Louis Aragon","date":"3 yıl önce","type":"translation","note":["(Aslını her okuyuşumda yeniden yorumlamak geliyordu içimden anadilde. Bugüneymiş artık. Keyifli okumalar.)"],"tr":["Sevmek, bilincini kaybedene dek sevmek","Bulmanın imkansızlığını anlatan kelimelerle.","Yoksa imkânı yok bu mevsimleri anlamanın","Seni ufkumdan ayrı düşleyerek","Ayrılık yarasının ötesinde","Kaybolmuş, acılar içinde bilinçsizce","Sensin harelenen sonunda","Yalnız sendeki aynalardır incinen hep","Mutluluğumsun, zayıflığım","Terk edilenim, hakaretler edilenimsin","Tenin yorgun bir savaşçının son anları şimdi","Sevmek, bilincini kaybedene dek sevmek","Bulmanın imkansızlığını anlatan kelimelerle.","Yoksa imkânı yok bu mevsimleri anlamanın","Seni ufkumdan ayrı düşleyerek","Ayrılık yarasının ötesinde","Kaybolmuş, acılar içinde bilinçsizce","Tutkularımızın bize bıraktığıdır","Ki bunca yorgunluk, açlık ve soğuk bundandır","Yaşadığımız dünyanın tüm sefaletine…","İnancım kalmışsa hala sevginedir tutunmalarım","Işığındır içimdeki cevheri aydınlatan","Ve artık karışmıştır gecelerine gecelerim","Sevmek, bilincini kaybedene dek sevmek","Bulmanın imkânsızlığını anlatan kelimelerle","Yoksa imkânı yok bu mevsimleri anlamanın","Seni ufkumdan ayrı düşleyerek","Ayrılık yarasının ötesinde","Kaybolmuş, acılar içinde bilinçsizce"],"orig":{"lang":"fr","title":"Aimer à perdre la raison","author":"Louis Aragon","body":["Aimer à n’en savoir que dire","A n’avoir que toi d’horizon","Et ne connaître de saisons","Que par la douleur du partir","Aimer a perdre la raison","Ah c’est toujours toi que l’on blesse","C’est toujours ton miroir brisé","Mon pauvre bonheur, ma faiblesse","Toi qu’on insulte et qu’on délaisse","Dans toute chair martyrisée","Aimer à perdre la raison","Aimer a n’en savoir que dire","A n’avoir que toi d’horizon","Et ne connaître de saisons","Que par la douleur du partir","Aimer a perdre la raison","La faim, la fatigue et le froid","Toutes les misères du monde","C est par mon amour que j’y crois","En elle je porte ma croix","Et de leurs nuits ma nuit se fonde","Aimer à perdre la raison","Aimer a n’en savoir que dire","A n’avoir que toi d’horizon","Et ne connaître de saisons","Que par la douleur du partir","Aimer a perdre la raison ."]}}]},{"id":"zahar","name":"Zahar","single":true,"poem":["unutmaksa bir yerde mahşer sayılır","henüz sonunda değiliz masalın","rüzgarın suya söylediği","ışığın kıyısında nöbetçi bir karanlık şimdi","","ben ki harflerden kurmuşum şehirleri","kağıdın elleri mi titrer bunu duyunca","yine de bilirsin kaç yalnızlık geçti ellerinden","kaç şehir, kaç hatıra","","sana, gözlerimizden geçen yolcusuz trenleri soruyorum","bir boşluktan taşar gibi zahar","işte, masanın köşesinde bekliyor düşlerimiz","","hep sakınırdım bu cümleleri","çünkü her şeyin cevap şekline dönüştüğü süreklilikte","içimizdeki dünya, beklerken kayboldu","","oysa ne çok soru vardı cevapsız kalan","bir uçurumun dibinde toplanmış eski bir yağmur gibi","cebimde taşıdığım yıldızların külüydü hepsi","","zahar dediğin işte bu:","gidenin ardından bıraktığı sesin","duvarlarda yankılanıp geriye dönmeyen hali","","sen yine de yaz","harflerin biriktirdiği o sessizlik","belki bir gün bir şiirin ortasında","kendi ağırlığıyla çöker içimize"],"coda":["Tüm gürültüsünü bu boşluğa yayan zamanın yıkıcı yanı neydi?","Yok olmanın eşiğine gelmiş bir yıldızın tarihini kim yazabilirdi?","Ya da neyin kopan parçasıydı dünya?","","Sorular kelimelerin gizli mahzenleri bunu anlıyorum.","Bir el, kemiğini saran kas kütlesiyle yine de yazmayı seçiyor."]}]}